import{c as a,Q as e,j as s,m as l}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"多人会议架构:Mesh / SFU / MCU","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/23-多人会议架构-Mesh-SFU-MCU.md","filePath":"mediaTechLearning/23-多人会议架构-Mesh-SFU-MCU.md","lastUpdated":1780887690000}'),i={name:"mediaTechLearning/23-多人会议架构-Mesh-SFU-MCU.md"};function n(p,t,d,o,r,h){return e(),s("div",null,[...t[0]||(t[0]=[l(`<h1 id="多人会议架构-mesh-sfu-mcu" tabindex="-1">多人会议架构:Mesh / SFU / MCU <a class="header-anchor" href="#多人会议架构-mesh-sfu-mcu" aria-label="Permalink to &quot;多人会议架构:Mesh / SFU / MCU&quot;">​</a></h1><p>一对一通话扩到多人,最大问题不是代码复杂,是带宽和编码压力指数上升。</p><blockquote><p>一句话先记住:<strong>Mesh 适合小房间,SFU 是现代会议主流,MCU 用服务器混流换客户端简单</strong>。</p></blockquote><hr><h2 id="一、mesh-每个人连每个人" tabindex="-1">一、Mesh:每个人连每个人 <a class="header-anchor" href="#一、mesh-每个人连每个人" aria-label="Permalink to &quot;一、Mesh:每个人连每个人&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A &lt;-&gt; B</span></span>
<span class="line"><span>A &lt;-&gt; C</span></span>
<span class="line"><span>B &lt;-&gt; C</span></span></code></pre></div><p>N 人时,每人上行要发 N-1 路。</p><table tabindex="0"><thead><tr><th>人数</th><th>每人上行</th></tr></thead><tbody><tr><td>2</td><td>1 路</td></tr><tr><td>4</td><td>3 路</td></tr><tr><td>8</td><td>7 路</td></tr></tbody></table><p>优点:</p><ul><li>架构简单</li><li>不需要媒体服务器</li><li>端到端路径短</li></ul><p>缺点:</p><ul><li>上行爆炸</li><li>CPU 编码压力大</li><li>房间稍大就不可用</li></ul><p>适合 2-4 人小房间 demo。</p><hr><h2 id="二、sfu-服务器转发媒体" tabindex="-1">二、SFU:服务器转发媒体 <a class="header-anchor" href="#二、sfu-服务器转发媒体" aria-label="Permalink to &quot;二、SFU:服务器转发媒体&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A -&gt; SFU -&gt; B/C/D</span></span>
<span class="line"><span>B -&gt; SFU -&gt; A/C/D</span></span></code></pre></div><p>每个客户端通常只上传一路,下载多路。服务器不解码混画面,主要转发 RTP 包。</p><p>优点:</p><ul><li>客户端上行压力低</li><li>延迟低</li><li>可做订阅控制</li><li>现代会议主流</li></ul><p>缺点:</p><ul><li>服务端带宽成本高</li><li>要处理转发、层级编码、质量控制</li><li>录制和混流要额外做</li></ul><hr><h2 id="三、mcu-服务器混流" tabindex="-1">三、MCU:服务器混流 <a class="header-anchor" href="#三、mcu-服务器混流" aria-label="Permalink to &quot;三、MCU:服务器混流&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A/B/C -&gt; MCU 解码混合 -&gt; 每人收到一路合成流</span></span></code></pre></div><p>优点:</p><ul><li>客户端最简单</li><li>每人只收一路</li><li>录制容易</li></ul><p>缺点:</p><ul><li>服务端要解码 + 合成 + 编码,CPU/GPU 贵</li><li>延迟更高</li><li>画面布局不灵活</li></ul><p>适合传统会议硬件、弱设备、固定布局录制。</p><hr><h2 id="四、simulcast-和-svc" tabindex="-1">四、Simulcast 和 SVC <a class="header-anchor" href="#四、simulcast-和-svc" aria-label="Permalink to &quot;四、Simulcast 和 SVC&quot;">​</a></h2><p>SFU 要解决不同用户带宽不同的问题。</p><p>Simulcast:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端同时发 180p / 360p / 720p 多路</span></span>
<span class="line"><span>SFU 给不同观众转不同层</span></span></code></pre></div><p>SVC:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一个编码流里包含多个空间 / 时间层</span></span>
<span class="line"><span>SFU 按层转发</span></span></code></pre></div><p>目的都是让差网络用户不拖垮好网络用户。</p><hr><h2 id="五、架构选择" tabindex="-1">五、架构选择 <a class="header-anchor" href="#五、架构选择" aria-label="Permalink to &quot;五、架构选择&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>推荐</th></tr></thead><tbody><tr><td>2 人通话</td><td>P2P</td></tr><tr><td>3-4 人小 demo</td><td>Mesh 可接受</td></tr><tr><td>正式多人会议</td><td>SFU</td></tr><tr><td>固定合成画面 / 传统会议</td><td>MCU 或 SFU + 录制合成</td></tr><tr><td>大规模直播</td><td>CDN / 直播系统,不是会议架构</td></tr></tbody></table><hr><h2 id="六、踩坑提醒" tabindex="-1">六、踩坑提醒 <a class="header-anchor" href="#六、踩坑提醒" aria-label="Permalink to &quot;六、踩坑提醒&quot;">​</a></h2><ol><li><strong>Mesh 做 10 人会议</strong>——上行直接炸。</li><li><strong>以为 SFU 不花钱</strong>——带宽成本很高。</li><li><strong>SFU 录制想当然</strong>——转发不等于自动有合成回放。</li><li><strong>不做订阅控制</strong>——没人看的视频还在下发。</li><li><strong>会议和直播混用架构</strong>——目标不同。</li></ol><p>下一篇:<code>24-SFU 心智:mediasoup / LiveKit / Janus.md</code>。</p>`,44)])])}const g=a(i,[["render",n]]);export{u as __pageData,g as default};
